+﻿using System;
+using System.Collections.Generic;
+using System.Linq;
+using System.Threading;
+using System.Threading.Tasks;
+using System.Web.Http;
+using GCCM.Common.SystemFramework;
+using ProjectSight.Common.Components;
+using ProjectSight.Common.Components.API;
+using ProjectSight.DataAccess;
+using System.Web;
+
+namespace ProjectSight.WebLayer.WebUI.API
+{
+    [RoutePrefix("{portfolioGuid:guid}/{projectId:int:min(1)}/globalsearch")]
+    public class GlobalSearchController : APIControllerBase
+    {
+        // Consider using Dependency Injection for CoreSystem if available
+        private readonly CoreSystem _coreSystem = new CoreSystem();
+
+        [HttpGet]
+        [Route("")] // Route: "{portfolioGuid}/{projectId}/globalsearch?term=...&types=..."
+        public async Task<IHttpActionResult> Search(Guid portfolioGuid, int projectId, [FromUri] string term, [FromUri] string types = "", CancellationToken cancellationToken = default)
+        {
+            var error = new ErrorEncountered();
+            var results = new List<GlobalSearchResult>(); // Ensure GlobalSearchResult is defined/referenced
+            var requestedTypes = new List<PrologTable.Types>();
+
+            try
+            {
+                // Base class method initializes 'RequestedBy'
+                await InitializeRequestAsync(portfolioGuid, projectId, cancellationToken: cancellationToken);
+
+                // --- Input Validation ---
+                if (string.IsNullOrWhiteSpace(term) || string.IsNullOrWhiteSpace(types))
+                {
+                    return Ok(results);
+                }
+                string searchTermLower = term.ToLowerInvariant();
+
+                // --- Parse and Validate Types ---
+                var typeIds = types.Split(',');
+                foreach (var typeIdStr in typeIds)
+                {
+                    if (int.TryParse(typeIdStr.Trim(), out int typeId) && Enum.IsDefined(typeof(PrologTable.Types), typeId))
+                    {
+                        var tableType = (PrologTable.Types)typeId;
+                        if (PrologTable.GetTableDetail(tableType)?.IsParentTable ?? false)
+                        {
+                            requestedTypes.Add(tableType);
+                        }
+                    }
+                }
+
+                if (requestedTypes.Count == 0)
+                {
+                    return Ok(results);
+                }
+
+                // --- Fetch Data Dynamically using CoreSystem ---
+                var fetchTasks = new List<Task<IPrologRecordItemBaseCollection>>();
+                var readRequest = new ReadPrologRecordRequest(RequestedBy.ClientType, true, true, false)
+                {
+                    OkToVerifyRecordSecurity = false // Keep false for POC
+                                                     // We don't need history or full children for this simple search
+                    ,
+                    DoNotReadHistory = true
+                };
+
+                // Get DataProvider correctly via RequestedBy (assuming it has CachedDataProvider)
+                var dataProvider = RequestedBy?.CachedDataProvider;
+                if (dataProvider == null)
+                {
+                    if (dataProvider == null)
+                    {
+                        error.Message = "Could not access data provider via RequestedBy.";
+                        return ReportAndReturnErrorResult(error.Message);
+                    }
+                }
+
+
+                foreach (var tableType in requestedTypes)
+                {
+                    var queryRequest = new QueryRequest { ProjectIDs = new List<int> { projectId } };
+                    fetchTasks.Add(_coreSystem.ReadRecordsForAPIAsync(tableType, RequestedBy, queryRequest, readRequest, error, cancellationToken));
+                }
+
+                var fetchedCollections = await Task.WhenAll(fetchTasks);
+
+                if (error.HasError) // Check error *after* await
+                {
+                    return ReportAndReturnErrorResult(error.Message);
+                }
+
+                // --- Filter In Memory using Metadata ---
+                foreach (var collection in fetchedCollections.Where(c => c != null))
+                {
+                    var tableType = collection.PrologTableType;
+                    // Get metadata via the dataProvider obtained earlier
+                    var tableDetail = dataProvider.GetTableDetailWithUDFs(tableType);
+                    if (tableDetail == null) continue;
+
+                    var searchableFields = tableDetail.SearchableTextFields?.Values ?? Enumerable.Empty<FieldDetail>();
+
+                    foreach (PrologRecordItemBase record in collection)
+                    {
+                        string snippet = null;
+                        bool match = false;
+                        string matchedFieldName = null;
+
+                        foreach (var fieldDetail in searchableFields)
+                        {
+                            // Use GetFieldValue and convert safely
+                            object fieldValueObj = record.GetFieldValue(fieldDetail.Name);
+                            string fieldValue = Convert.ToString(fieldValueObj);
+
+                            if (!string.IsNullOrEmpty(fieldValue) && fieldValue.IndexOf(searchTermLower, StringComparison.InvariantCultureIgnoreCase) >= 0)
+                            {
+                                match = true;
+                                matchedFieldName = fieldDetail.DisplayName ?? fieldDetail.Name;
+                                snippet = GetSnippet(fieldValue, term);
+                                break;
+                            }
+                        }
+
+                        if (match)
+                        {
+                            string recordNumber = Convert.ToString(record.GetFieldValue(tableDetail.RecordNumber));
+                            string title = Convert.ToString(record.GetFieldValue("Subject")) ?? Convert.ToString(record.GetFieldValue("Title")) ?? Convert.ToString(record.GetFieldValue("Name")) ?? $"ID: {record.PrologRecordId}";
+                            string recordTypeName = Enum.GetName(typeof(PrologTable.Types), tableType);
+
+                            // Ensure GlobalSearchResult is defined/referenced
+                            results.Add(new GlobalSearchResult
+                            {
+                                RecordId = record.PrologRecordId.ToString(),
+                                RecordType = recordTypeName,
+                                DisplayText = $"{recordTypeName} {recordNumber ?? record.PrologRecordId.ToString()}: {title}".Trim(),
+                                Snippet = $"[{matchedFieldName ?? "Field"}]: {snippet ?? ""}",
+                                NavigationUrl = GenerateNavigationUrl(projectId, tableType, record.PrologRecordId)
+                            });
+                        }
+                    }
+                }
+
+                // --- Simple Ordering & Limit ---
+                var finalResults = results
+                    .OrderBy(r => r.RecordType)
+                    .ThenBy(r => r.DisplayText)
+                    .Take(50)
+                    .ToList();
+
+                return Ok(finalResults);
+            }
+            catch (Exception ex)
+            {
+                if (Logger != null)
+                {
+                    Logger.ReportError(ex, this);
+                }
+                else
+                {
+                    System.Diagnostics.Debug.WriteLine($"Error in GlobalSearch: {ex}");
+                }
+                error.Message = "An unexpected error occurred during the search.";
+                return ReportAndReturnErrorResult(error.Message);
+            }
+        }
+
+        private string GetSnippet(string text, string term, int contextLength = 50)
+        {
+            if (string.IsNullOrEmpty(text)) return string.Empty;
+            int index = text.IndexOf(term, StringComparison.InvariantCultureIgnoreCase);
+            if (index == -1) return text.Length > contextLength * 2 ? text.Substring(0, contextLength * 2) + "..." : text;
+            int start = Math.Max(0, index - contextLength);
+            int end = Math.Min(text.Length, index + term.Length + contextLength);
+            int length = end - start;
+            string snippet = text.Substring(start, length);
+            if (start > 0) snippet = "..." + snippet;
+            if (end < text.Length) snippet = snippet + "...";
+            return snippet;
+        }
+
+        // Helper to generate navigation URLs (NEEDS CUSTOMIZATION)
+        private string GenerateNavigationUrl(int projectId, PrologTable.Types tableType, int recordId)
+        {
+            // Get the string name of the record type from the enum value
+            string recordTypeName = tableType.ToString();
+
+            // Determine the specific DEF page name for the record type.
+            string defPageName = GetDefPageNameForType(recordTypeName);
+            if (string.IsNullOrEmpty(defPageName))
+            {
+                return "#"; // Fallback if type not supported
+            }
+
+            // Use the context from APIControllerBase to get the application path
+            string applicationPath = this.ApplicationPath; // From APIControllerBase
+
+            // Get Org ID from the base controller context
+            string orgId = this.CurrentOrganizationID.ToString(Support.IGNITION_ORGANIZATION_GUID_FORMAT_FOR_URL);
+
+            // Convert projectId and recordId to strings for the URL
+            string projectIdStr = projectId.ToString();
+            string recordIdStr = recordId.ToString();
+
+            // Construct the URL based on the pattern found in GetDEFURL
+            string url = $"{applicationPath.TrimEnd('/')}/{defPageName}" +
+                         $"?{WebAppSupport.QUERY_VALUE_ACTION}={WebAppSupport.GetActionValueForActionType(Support.RecordActionTypes.Edit)}" +
+                         $"&{WebAppSupport.QUERY_VALUE_ORGANIZATION_ID}={orgId}" +
+                         $"&{WebAppSupport.QUERY_VALUE_PROJECT_ID}={projectIdStr}" + // Use the passed projectId
+                         $"&{WebAppSupport.QUERY_VALUE_PRIMARY_KEY_ID}={recordIdStr}"; // Use the passed recordId
+
+            // Add logic for types that might not need Org or Project ID if necessary
+
+            return url;
+        }
+
+        // Helper method to map record type name to DEF page name
+        private string GetDefPageNameForType(string recordType)
+        {
+            switch (recordType)
+            {
+                case nameof(PrologTable.Types.Drawing):
+                    return "Drawing_v7.aspx";
+
+                case nameof(PrologTable.Types.RFI):
+                    return "RFIDEF.aspx";
+
+                case nameof(PrologTable.Types.SubmittalRegister):
+                    return "SubmittalRegisterDEF.aspx";
+
+                case nameof(PrologTable.Types.PunchList):
+                    return "PunchListDEF.aspx";
+
+                case nameof(PrologTable.Types.Issue):
+                    return "IssueDEF.aspx";
+
+                case nameof(PrologTable.Types.DailyReport):
+                    return "DailyReportDEF.aspx";
+
+                // --- Add other record types supported by your search here ---
+                // case nameof(PrologTable.Types.Meeting):
+                //     return "MeetingDEF.aspx";
+
+                default:
+                    return null;
+            }
+        }
+    }
+}
