+<body>
+    <h1>Global Search POC Test</h1>
+
+    <label for="portfolioGuid">Portfolio GUID:</label>
+    <input type="text" id="portfolioGuid" value="c76ac9a9-c9f3-4ab1-a87a-b99c2a7dbf9b"> <!-- *** REPLACE with YOUR GUID *** -->
+
+    <label for="projectId">Project ID:</label>
+    <input type="number" id="projectId" value="2"> <!-- *** REPLACE with YOUR Project ID *** -->
+
+    <label for="searchTerm">Search Term:</label>
+    <input type="text" id="searchTerm" placeholder="Enter search term...">
+
+    <label for="recordTypes">Record Type IDs (comma-separated):</label>
+    <input type="text" id="recordTypes" value="8,56" placeholder="e.g., 8,56 for RFI, Drawing"> <!-- Default: RFI=8, Drawing=56 -->
+    <small>Common IDs: RFI=8, Drawing=56, SubmittalRegister=45, PunchList=49, Issue=75, DailyReport=38</small>
+
+    <button onclick="performSearch()">Search</button>
+
+    <h2>Results:</h2>
+    <div id="error"></div>
+    <pre id="results"></pre>
+
+    <script>
+        async function performSearch() {
+            const portfolioGuid = document.getElementById('portfolioGuid').value.trim();
+            const projectId = document.getElementById('projectId').value.trim();
+            const term = document.getElementById('searchTerm').value.trim();
+            const types = document.getElementById('recordTypes').value.trim();
+            const resultsDiv = document.getElementById('results');
+            const errorDiv = document.getElementById('error');
+
+            resultsDiv.textContent = 'Loading...';
+            errorDiv.textContent = '';
+
+            // Construct the API URL using the application's base path
+            const apiUrl = `/ProjectSightWebClient/api/${portfolioGuid}/${projectId}/globalsearch?term=${encodeURIComponent(term)}&types=${encodeURIComponent(types)}`;
+
+            try {
+                const response = await fetch(apiUrl);
+
+                if (!response.ok) {
+                    let errorText = `HTTP error! Status: ${response.status}`;
+                    try {
+                        const errorJson = await response.json();
+                        errorText += ` - ${errorJson.message || errorJson.error || JSON.stringify(errorJson)}`;
+                    } catch (e) {
+                         // Ignore if response is not JSON
+                    }
+                    throw new Error(errorText);
+                }
+
+                const data = await response.json();
+                // Check if the API returned an error within its structure
+                if (data && data.error) {
+                     throw new Error(`API Error: ${data.error} (Code: ${data.code || 'N/A'})`);
+                }
+                // Display the raw JSON result
+                resultsDiv.textContent = JSON.stringify(data.value || data, null, 2); // Show 'value' if structured response, else show whole object
+
+            } catch (error) {
+                console.error('Search failed:', error);
+                errorDiv.textContent = `Error: ${error.message}`;
+                resultsDiv.textContent = ''; // Clear loading message
+            }
+        }
+    </script>
+</body>
+</html>
+

